mapper.update:
UPDATE room 
SET current_members = #{currentMembers},
    version = version + 1,
    update_time = NOW()
WHERE room_id = #{roomId}
AND version = #{version}

mapper.select:
SELECT r.room_id AS roomId, r.room_code AS roomCode, r.room_name AS roomName, r.description AS description, r.max_members AS maxMembers, r.current_members AS currentMembers, r.owner_id AS ownerId, r.status AS status, r.expire_time AS expireTime, r.create_time AS createTime, r.update_time AS updateTime, r.password_mode AS passwordMode, r.password_visible AS passwordVisible, rm.role AS userRole, rm.join_time AS joinTime FROM room r INNER JOIN room_member rm ON r.room_id = rm.room_id AND rm.user_id = #{userId} AND rm.leave_time IS NULL
AND r.status = #{status}
AND r.status IN (0, 1, 2)
AND r.status = 0
ORDER BY r.create_time DESC LIMIT #{limit} OFFSET #{offset}
